import{_ as o,o as c,c as a,a2 as d}from"./chunks/framework.DvFsUg-r.js";const m=JSON.parse('{"title":"/blog/ 를 떼다 — 사이트를 coffeeman1.github.io 루트로 옮긴 기록","description":"","frontmatter":{"slug":"deploy-root-domain","title":"/blog/ 를 떼다 — 사이트를 coffeeman1.github.io 루트로 옮긴 기록","authors":[],"tags":["github-pages","vitepress","deploy","cross-repo","spec-kit","sdd"],"created":"2026-06-03 22:35 (KST)","date":"2026-06-03T13:35:00.000Z"},"headers":[],"relativePath":"journal/2026-06-03-deploy-root-domain.md","filePath":"journal/2026-06-03-deploy-root-domain.md","lastUpdated":1781092690000}'),t={name:"journal/2026-06-03-deploy-root-domain.md"};function s(r,e,i,l,n,p){return c(),a("div",null,[...e[0]||(e[0]=[d('<p>&quot;배포경변경&quot; 한 줄로 Spec Kit 한 바퀴를 돌렸다. 결과만 말하면, 설계 저널 사이트가 이제 <code>coffeeman1.github.io/blog/</code> 가 아니라 <strong><code>coffeeman1.github.io/</code> 루트</strong>에서 열린다. <code>main</code> 에 푸시하면 거기로 자동 배포된다. 이 글은 그 경로를 바꾸면서 마주친 결정들과, 중간에 끼어든 사고 두 건의 기록이다.</p><h2 id="clarify-가-진짜-결정을-끄집어냈다" tabindex="-1">clarify 가 진짜 결정을 끄집어냈다 <a class="header-anchor" href="#clarify-가-진짜-결정을-끄집어냈다" aria-label="Permalink to &quot;clarify 가 진짜 결정을 끄집어냈다&quot;">​</a></h2><p>specify 의 입력은 &quot;배포경변경&quot; 이 전부였다. &quot;배포 경로 변경&quot; 이라는 짐작은 가지만, 무엇을 어디로 바꾸는지가 비어 있었다. clarify 가 세 가지를 확정했다.</p><ol><li><strong>어떻게 루트로?</strong> — 지금 저장소는 <code>coffeeman1/blog</code>, 즉 <em>프로젝트 페이지</em>라 구조적으로 <code>/blog/</code> 하위 경로로만 게시된다. 루트는 <em>사용자 페이지</em> (<code>coffeeman1.github.io</code> 라는 이름의 저장소)만 차지할 수 있다. 그래서 소스는 <code>blog</code> 에 그대로 두고, <strong>CI 가 빌드 산출물만 <code>coffeeman1.github.io</code> 저장소로 크로스-레포 푸시</strong>하기로 했다. 소스와 게시를 분리하는 쪽.</li><li><strong>옛 <code>/blog/</code> 는?</strong> — 리다이렉트도, 안내도 두지 않고 그냥 닫는다(404 허용).</li><li><strong>게시 저장소에 이미 있던 옛 Hexo 블로그는?</strong> — 이 사이트로 완전히 대체. 옛 글은 이미 <code>/blog-archive/</code> 로 임포트돼 있으니 따로 보존할 게 없다.</li></ol><p>이 셋이 정해지자 plan 은 거의 기계적으로 풀렸다. 바뀌는 표면은 딱 둘 — <code>config.mts</code> 의 <code>base</code> 와 <code>publish-blog.yml</code> — 그리고 사람 손이 필요한 인프라 (배포키·게시 저장소 Pages 설정) 였다.</p><h2 id="크로스-레포-배포의-실제" tabindex="-1">크로스-레포 배포의 실제 <a class="header-anchor" href="#크로스-레포-배포의-실제" aria-label="Permalink to &quot;크로스-레포 배포의 실제&quot;">​</a></h2><p>핵심은 <code>publish-blog.yml</code> 을 갈아끼우는 일이었다. 기존엔 GitHub Pages 네이티브 액션(<code>configure-pages</code> → <code>upload-pages-artifact</code> → <code>deploy-pages</code>)으로 <em>이</em> 저장소의 Pages(=<code>/blog/</code>)에 올렸다. 이건 같은 저장소 전용이라 루트로는 못 보낸다.</p><p>대신 <code>peaceiris/actions-gh-pages</code> 로 바꿨다.</p><ul><li><code>external_repository: coffeeman1/coffeeman1.github.io</code> — 다른 저장소로 푸시</li><li><code>force_orphan: true</code> — 게시 브랜치를 단일 커밋으로 통째 교체. 옛 Hexo 잔존물 없이 깨끗이 갈아엎고, 히스토리도 안 불어난다.</li><li>인증은 <strong>SSH 배포키</strong>. 공개키는 게시 저장소 Deploy key(write), 개인키는 소스 저장소 secret <code>ACTIONS_DEPLOY_KEY</code>. PAT 보다 권한이 한 저장소로 좁아 안전하다.</li></ul><p>그리고 <code>base: &#39;/blog/&#39;</code> → <code>&#39;/&#39;</code>. 사용자 페이지는 루트에서 서빙되니 base 접두사가 없어야 자산 경로가 맞는다. 다행히 콘텐츠의 내부 링크는 전부 루트 절대경로라 base 한 줄만 고치면 됐다. (<code>/blog-archive/blog/...</code> 같은 경로가 grep 에 걸려 잠깐 긴장했지만, 그건 <em>콘텐츠 섹션</em> 경로지 배포 base 가 아니었다.)</p><h2 id="컷오버에서-걸린-함정-—-pages-가-docs-를-보고-있었다" tabindex="-1">컷오버에서 걸린 함정 — Pages 가 <code>/docs</code> 를 보고 있었다 <a class="header-anchor" href="#컷오버에서-걸린-함정-—-pages-가-docs-를-보고-있었다" aria-label="Permalink to &quot;컷오버에서 걸린 함정 — Pages 가 `/docs` 를 보고 있었다&quot;">​</a></h2><p>배포키를 <code>gh</code> 로 등록하고 첫 배포를 브랜치에서 돌렸다. 빌드도 게시도 초록불. 그런데 게시 저장소의 Pages 설정을 보니 source 가 <code>main</code> 브랜치의 <strong><code>/docs</code></strong> 폴더였다 — 옛 Hexo 가 거기 있었던 것이다. 우리는 <code>main</code> <em>루트</em>에 dist 를 올리는데. 그래서 Pages source 를 <code>/docs</code> → <code>/(root)</code> 로 바꾸고 빌드를 한 번 더 태웠다. 이걸 안 봤으면 &quot;배포는 성공했는데 사이트는 옛것&quot; 인 채로 한참 헤맸을 것이다.</p><p>결과: 루트 <code>200</code>, 자산은 <code>/assets/...</code> 루트 상대경로, 주요 섹션 전부 <code>200</code>, 옛 <code>/blog/</code> 는 <code>blog</code> 저장소 Pages 를 끄자 <code>404</code>. 의도대로다.</p><h2 id="중간에-main-이-움직였다" tabindex="-1">중간에 main 이 움직였다 <a class="header-anchor" href="#중간에-main-이-움직였다" aria-label="Permalink to &quot;중간에 main 이 움직였다&quot;">​</a></h2><p>PR 을 머지하려는데 &quot;cleanly merge 불가&quot; 가 떴다. 작업하는 사이 <code>013-docs-validation</code> 이 main 에 들어와 있었다. 충돌은 Spec Kit 이 자동 관리하는 포인터 둘 — <code>CLAUDE.md</code> 의 plan 링크와 <code>.specify/feature.json</code> — 뿐이었다. 014 는 이미 끝난(<code>status: done</code>) 기능이라 &quot;현재 기능&quot; 포인터를 가로챌 이유가 없다. 그래서 두 파일은 <strong>main(013) 쪽을 그대로</strong> 받고, 내 코드 변경만 살렸다.</p><p>덤으로 013 이 들여온 <code>scripts/validate-docs.mjs</code> 로 병합 트리를 검증했다 — sync 후 strict 빌드(C1)에 프런트매터(C2)·정렬(C3)·스타일(C4)까지. 차단 0, 경고 0. main 푸시가 새 워크플로로 자동 배포되는 것까지 확인하고 마무리했다.</p><h2 id="작은-교훈-하나" tabindex="-1">작은 교훈 하나 <a class="header-anchor" href="#작은-교훈-하나" aria-label="Permalink to &quot;작은 교훈 하나&quot;">​</a></h2><p>커밋 메시지를 넣다가 첫 줄에 <code>@</code> 가 끼었다. 이 환경엔 Bash 도구와 PowerShell 도구가 둘 다 있는데, Bash 에 PowerShell here-string(<code>@&#39;...&#39;@</code>)을 써서 <code>@</code> 가 리터럴로 남은 것. 멀티라인 메시지는 파일로 빼서 <code>-F</code> 로 넘기거나 POSIX here-doc 을 쓰는 게 답이다. 도구가 둘이면 문법도 둘이라는 걸 잊지 말 것.</p><hr><p>블로그 없는 도구로 만든 블로그가, 이제 제 도메인의 첫 화면이 됐다. <code>specs/014-deploy-root-domain/</code> 에 spec·plan·research·contracts·quickstart·tasks 가 다 남아 있다.</p>',20)])])}const u=o(t,[["render",s]]);export{m as __pageData,u as default};
